patch:
--- a/alu.v
+++ b/alu.v
@@ -1,8 +1,8 @@
 module simple_alu(
   input [31:0] operand_a, operand_b,
   input [2:0] opcode,
   output reg [31:0] result
 );
-  always @(operand_a or opcode) begin
+  always @(*) begin
     case(opcode)
       3'b000: result = operand_a + operand_b;
       3'b001: result = operand_a - operand_b;

before_code:
module simple_alu(
  input [31:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [31:0] result
);
  always @(operand_a or opcode) begin
    case(opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      3'b011: result = operand_a | operand_b;
      3'b100: result = operand_a ^ operand_b;
      default: result = 32'b0;
    endcase
  end
endmodule

after_code:
module simple_alu(
  input [31:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [31:0] result
);
  always @(*) begin
    case(opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      3'b011: result = operand_a | operand_b;
      3'b100: result = operand_a ^ operand_b;
      default: result = 32'b0;
    endcase
  end
endmodule
